MRFSipeAnalysisCmd::MRFSipeAnalysisCmd() :
CATStateCommand ("MRFSipeAnalysisCmd", CATDlgEngOneShot, CATCommandModeShared)
//  Valid states are CATDlgEngOneShot and CATDlgEngRepeat
, _pSipeAnalysisDlg(NULL)
, _pApplicationFrame(NULL)
, _pEditor(NULL)
, _pHSO(NULL)
, _pViewer(NULL)
, _pSipesSetDialogAgent(NULL)
, _pRefinedSipesDialogAgent(NULL)
, _pSipeRefinerDialogAgent(NULL)
, _pSegmentSetDialogAgent(NULL)
, _pSipeSetPathElementAgent(NULL)
, _pSipeRefinerPathElementAgent(NULL)
, _pRefinedSipesPathElementAgent(NULL)
, _pSegmentSetPathElementAgent(NULL)
, _pSipeSetPathElement(NULL)
, _pSipeRefinerPathElement(NULL)
, _pRefinedSipesPathElementList(NULL)
, _pSegmentSetPathElement(NULL)
, _pRefinedSipesDlgCloseAgent(NULL)
, _pTWIsDlgCloseAgent(NULL)
, _pRefinedSipesDlgAgent(NULL)
, _pTWIsDialolgAgent(NULL)
, _pTWIsDlgAgent(NULL)
, _pTWIsPathElementAgent(NULL)
, _spMechanicalPart(NULL_var)
{
	_pApplicationFrame = CATApplicationFrame::GetFrame();
	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();

		CATPathElement  oActivePath = _pEditor->GetUIActiveObject();
		oActivePath.InitToLeafElement();
		CATBaseUnknown_var spCBUOnCurrObject = oActivePath.NextFatherElement();

		if (NULL_var != spCBUOnCurrObject)
		{
			CATIMmiUsePrtPart * piPrtPart = NULL;
			spCBUOnCurrObject->QueryInterface(IID_CATIMmiUsePrtPart, (void**)&piPrtPart);
			if (NULL != piPrtPart && NULL_var == _spMechanicalPart)
			{
				_spMechanicalPart = piPrtPart;
				piPrtPart->Release();  piPrtPart = NULL;
			}
		}
	}

	_pViewer = CATViewer::GetCurrentViewer();
	_pSipeAnalysisDlg = new MRFSipeAnalysisDlg();
	_SipeAnalysisType = 0;
}

